  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "A wiſſu-augſtaja Gud-ribâ irr fawu Nammu uſtaifijſti/ wiſſa irr fa-wus ſeptius Pihlarus uszir-tuſt."
    },
    {
      "n": 2,
      "column": "left",
      "text": "Wiſſa irr fawus kaujamus Lohpus kawuſi/ fawu Wi-hnu jaukuſt/ ir fawu Galdu irr wiſſa fataifijſt."
    },
    {
      "n": 3,
      "column": "left",
      "text": "Wiſſa irr fawas Kalpo-nes iſjuhtijſt/ ta aizina uſ ta Pilſfahta Augſtumeem un Wir& Galleem."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Kurſch irr neprattigs/ tas lai ſchurp greeschahs. Uſ to Geſſi faſſa wiſſa."
    },
    {
      "n": 5,
      "column": "left",
      "text": "Nahzeet/ ehdeet no man-nas Maises/ un dſerreet no ta Wiſna/ ko es eſmu fajaukuſi."
    },
    {
      "n": 6,
      "column": "left",
      "text": "Atſtahjeet tohs Nepratti-gus un dſihwojeet/un ſtatgajeet uſ to Zeltu tahs Sapraſchanaſ."
    },
    {
      "n": 7,
      "column": "left",
      "text": "Kaſ to Mehdiſaju pahr-mahza/ tas dabbu uſ few Kau-nu/ un kaſ to Besdeewigu va-mahza/ tas dabbu uſ few Ap-fineetchanu."
    },
    {
      "n": 8,
      "column": "left",
      "text": "Me pahrmahzi to Mehdi-taju/ ka wiſſch tew ne eenihd/ pahrmahzi to Prahtneeku / tad wiſſch tew miſſchs."
    },
    {
      "n": 10,
      "column": "right",
      "text": "Ta KUNGA Bihjaſch-na irr tahs Gudribas Ceſakums/ un tahs Atſihſchan(Eſahkums) irr ſwehtu LeeNopraſchana."
    },
    {
      "n": 11,
      "column": "right",
      "text": "Jo zaar manni taps twas Deenas dauds/ un Dſihnbas Gaddi taps tew peeliſtti."
    },
    {
      "n": 12,
      "column": "right",
      "text": "Eſſi tu gudrs/ tad eſſitewin gudrs/ un eſſi tu kabMehditajs/ tad tu weens po to neſſift."
    },
    {
      "n": 13,
      "column": "right",
      "text": "Weena geſſiga Seeirr aplama/ tehrſe/ un ne finneueka."
    },
    {
      "n": 14,
      "column": "right",
      "text": "Ta fehſch fawa NamDuwts / uſ weenit Krehpilsfahta Augſtumoſ."
    },
    {
      "n": 15,
      "column": "right",
      "text": "Un aizina tohs/ kaſZelta fezzen eet/ kaſ pareiſisaweem Zelteem staiga."
    },
    {
      "n": 16,
      "column": "right",
      "text": "Kaſ irr Nenojehga/ laid greeschahs ſchurp/ un uſGeſſi faſſa wiſſa:"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Tas ſagts Uhdensfaldis/ un ta noſlehpta Ma-irr gahrda."
    },
    {
      "n": 18,
      "column": "right",
      "text": "Bet tas ne ſinna/ ka tMirroni irr/ un wiſſas Anatee Elles Dſittumoſ."
    }
  ],
  "confidence": "high",
  "notes": ""
}
